// Function to add video data to existing actors
export const addVideoDataToActors = (actors: any[]) => {
  return actors.map((actor, index) => {
    // Add videos to some actors for testing
    if (index % 3 === 0) {
      return {
        ...actor,
        submissionVideos: [
          {
            url: `https://www.youtube.com/watch?v=test${index}`,
            embedUrl: `https://www.youtube.com/embed/test${index}`,
            platform: "youtube",
          },
        ],
      }
    } else if (index % 4 === 0) {
      return {
        ...actor,
        submissionVideos: [
          {
            url: `https://vimeo.com/test${index}`,
            embedUrl: `https://player.vimeo.com/video/test${index}`,
            platform: "vimeo",
          },
          {
            url: `https://www.youtube.com/watch?v=test${index}b`,
            embedUrl: `https://www.youtube.com/embed/test${index}b`,
            platform: "youtube",
          },
        ],
      }
    }
    return actor
  })
}
